    }

    @Test
    @DisplayName("elements with multiple elements invokes Node overload for each in order")
    public void test_TC11_O2() {
        // three elements => three calls to overload
        Elements elements = new Elements(
                new Element("a"),
                new Element("b"),
                new Element("c")
        );
        TrackVisitor visitor = new TrackVisitor();
        NodeTraversor.traverse(visitor, elements);
        assertEquals(3, visitor.headCalls.size());
        assertEquals(3, visitor.tailCalls.size());
        assertEquals(List.of("a:0","b:0","c:0"), visitor.headCalls);
        assertEquals(List.of("a:0","b:0","c:0"), visitor.tailCalls);
    }

    @Test
    @DisplayName("deep nested tree triggers multiple ascend and descend steps across depth>1")
    public void test_TC12_O1() {
        // depth 2 tree => paths through B12 descend twice then ascend
        Element root = new Element("r");
        Element c1 = new Element("c");
        Element c2 = new Element("c2");
        root.appendChild(c1);
        c1.appendChild(c2);
        TrackVisitor visitor = new TrackVisitor();
        NodeTraversor.traverse(visitor, root);
        List<String> expHead = List.of("r:0","c:1","c2:2");
        List<String> expTail = List.of("c2:2","c:1","r:0");
        assertEquals(expHead, visitor.headCalls);
        assertEquals(expTail, visitor.tailCalls);
    }
